    16→
    17→#include "logger/log.h"
    18→#include "command/android/cmd_class.h"
    19→#include "command/android/cmd_print.h"
    20→#include "dex/modifiers.h"
    21→#include "android.h"
    22→#include "runtime/mirror/iftable.h"
    23→#include "api/core.h"
    24→#include <stdio.h>
    25→#include <unistd.h>
    26→#include <getopt.h>
    27→#include <vector>
    28→
    29→int ClassCommand::prepare(int argc, char* const argv[]) {
    30→    if (!CoreApi::IsReady() || !Android::IsSdkReady())
    31→        return Command::FINISH;
    32→
    33→    options.dump_all = true;
    34→    options.show_flag = 0;
    35→    options.format_hex = false;
    36→    options.obj_each_flags = 0;
    37→    options.total_classes = 0;
    38→
    39→    int opt;
    40→    int option_index = 0;
    41→    optind = 0; // reset
    42→    static struct option long_options[] = {
    43→        {"method",  no_argument,       0,  'm'},
    44→        {"static",  no_argument,       0,  's'},
    45→        {"impl",    no_argument,       0,  'i'},
    46→        {"field",   no_argument,       0,  'f'},
    47→        {"hex",     no_argument,       0,  'x'},
    48→        {"app",     no_argument,       0,   1 },
    49→        {"zygote",  no_argument,       0,   2 },
    50→        {"image",   no_argument,       0,   3 },
    51→        {"fake",    no_argument,       0,   4 },
    52→        {0,         0,                 0,   0 },
    53→    };
    54→
    55→    while ((opt = getopt_long(argc, argv, "msifx",
    56→                long_options, &option_index)) != -1) {
    57→        switch (opt) {
    58→            case 'm':
    59→                options.show_flag |= SHOW_METHOD;
    60→                break;
    61→            case 's':
    62→                options.show_flag |= SHOW_STATIC;
    63→                break;
    64→            case 'i':
    65→                options.show_flag |= SHOW_IMPL;
    66→                break;
    67→            case 'f':
    68→                options.show_flag |= SHOW_FIELD;
    69→                break;
    70→            case 'x':
    71→                options.format_hex = true;
    72→                break;
    73→            case 1:
    74→                options.obj_each_flags |= Android::EACH_APP_OBJECTS;
    75→                break;
    76→            case 2:
    77→                options.obj_each_flags |= Android::EACH_ZYGOTE_OBJECTS;
    78→                break;
    79→            case 3:
    80→                options.obj_each_flags |= Android::EACH_IMAGE_OBJECTS;
    81→                break;
    82→            case 4:
    83→                options.obj_each_flags |= Android::EACH_FAKE_OBJECTS;
    84→                break;
    85→        }
    86→    }
    87→    options.optind = optind;
    88→
    89→    if (!options.obj_each_flags) {
    90→        options.obj_each_flags |= Android::EACH_APP_OBJECTS;
    91→        options.obj_each_flags |= Android::EACH_ZYGOTE_OBJECTS;
    92→        options.obj_each_flags |= Android::EACH_IMAGE_OBJECTS;
    93→        options.obj_each_flags |= Android::EACH_FAKE_OBJECTS;
    94→    }
    95→
    96→    if (options.optind < argc) {
    97→        options.dump_all = false;
    98→        options.show_flag = !options.show_flag ? SHOW_ALL : options.show_flag;
    99→    }
   100→
   101→    Android::Prepare();
   102→    return Command::ONCHLD;
   103→}
   104→
   105→int ClassCommand::main(int argc, char* const argv[]) {
   106→    const char* classname = argv[options.optind];
   107→    auto callback = [&](art::mirror::Object& object) -> bool {
   108→        return PrintClass(object, classname);
   109→    };
   110→
   111→    try {
   112→        if (!options.dump_all) {
   113→            art::mirror::Object obj = Utils::atol(argv[options.optind]);
   114→            if (obj.Ptr() && obj.IsValid() && obj.IsClass()) {
   115→                art::mirror::Class thiz = obj;
   116→                PrintPrettyClassContent(thiz, options);
   117→            } else {
   118→                Android::ForeachObjects(callback, options.obj_each_flags, false);
   119→            }
   120→        } else {
   121→            Android::ForeachObjects(callback, options.obj_each_flags, false);
   122→        }
   123→    } catch(InvalidAddressException& e) {
   124→        LOGW("The statistical process was interrupted!\n");
   125→    }
   126→    return 0;
   127→}
   128→
   129→bool ClassCommand::PrintClass(art::mirror::Object& object, const char* classname) {
   130→    if (!object.IsClass())
   131→        return false;
   132→
   133→    art::mirror::Class thiz = object;
   134→    if (options.dump_all) {
   135→        options.total_classes++;
   136→        LOGI("[%" PRId64 "] " ANSI_COLOR_LIGHTYELLOW "0x%" PRIx64 "" ANSI_COLOR_LIGHTCYAN " %s\n" ANSI_COLOR_RESET,
   137→                options.total_classes, thiz.Ptr(), thiz.PrettyDescriptor().c_str());
   138→        if (options.show_flag) PrintPrettyClassContent(thiz, options);
   139→    } else if (thiz.PrettyDescriptor() == classname) {
   140→        PrintPrettyClassContent(thiz, options);
   141→    }
   142→
   143→    return false;
   144→}
   145→
   146→void ClassCommand::PrintPrettyClassContent(art::mirror::Class& clazz, ClassCommand::Options& options) {
   147→    LOGI(ANSI_COLOR_LIGHTYELLOW "[0x%" PRIx64 "]\n" ANSI_COLOR_RESET, clazz.Ptr());
   148→    art::mirror::Class super = clazz.GetSuperClass();
   149→    art::mirror::IfTable& iftable = clazz.GetIfTable();
   150→    int32_t ifcount = (iftable.Ptr() && iftable.IsValid()) ? iftable.Count() : 0;
   151→    bool needEnd = false;
   152→    if (super.Ptr()) {
   153→        LOGI(ANSI_COLOR_LIGHTGREEN "%s" "class " ANSI_COLOR_RESET "%s" ANSI_COLOR_LIGHTGREEN " extends " ANSI_COLOR_RESET "%s" " {\n",
   154→                art::PrettyClassAccessFlags(clazz.GetAccessFlags()).c_str(),
   155→                clazz.PrettyDescriptor().c_str(), super.PrettyDescriptor().c_str());
   156→    } else {
   157→        LOGI(ANSI_COLOR_LIGHTGREEN "%s" "class " ANSI_COLOR_RESET "%s" " {\n",
   158→                art::PrettyClassAccessFlags(clazz.GetAccessFlags()).c_str(),
   159→                clazz.PrettyDescriptor().c_str());
   160→    }
   161→    if (ifcount > 0 && (options.show_flag & SHOW_IMPL)) {
   162→        LOGI(ANSI_COLOR_LIGHTCYAN "  // Implements:\n" ANSI_COLOR_RESET);
   163→        for (int i = 0; i < ifcount; ++i) {
   164→            art::mirror::Class interface = iftable.GetInterface(i);
   165→            try {
   166→                LOGI("    %s\n", interface.PrettyDescriptor().c_str());
   167→            } catch(InvalidAddressException& e) {
   168→                LOGI("    java.lang.Class<0x%" PRIx64 ">\n", interface.Ptr());
   169→            }
   170→        }
   171→        needEnd = true;
   172→    }
   173→    std::string format = PrintCommand::FormatSize(clazz.SizeOf());
   174→    std::string format_nonenter = format;
   175→    format.append("\n");
   176→
   177→    art::mirror::Class current = clazz;
   178→    if (clazz.NumStaticFields() && (options.show_flag & SHOW_STATIC)) {
   179→        if (needEnd) ENTER();
   180→        LOGI(ANSI_COLOR_LIGHTCYAN "  // Class static fields:\n" ANSI_COLOR_RESET);
   181→        needEnd = true;
   182→    }
   183→    std::vector<art::ArtField> fields;
   184→    auto print_static_field = [&](art::ArtField& field) -> bool {
   185→        fields.push_back(field);
   186→        return false;
   187→    };
   188→    if ((options.show_flag & SHOW_STATIC)) {
   189→        Android::ForeachStaticField(current, print_static_field);
   190→        std::sort(fields.begin(), fields.end(), art::ArtField::Compare);
   191→
   192→        PrintCommand::Options print_options = {
   193→            .format_hex = options.format_hex,
   194→        };
   195→
   196→        for (auto& field : fields) {
   197→            PrintCommand::PrintField(format_nonenter.c_str(), current, clazz, field, print_options);
   198→        }
   199→        fields.clear();
   200→    }
   201→
   202→    if (clazz.NumInstanceFields() && (options.show_flag & SHOW_FIELD)) {
   203→        if (needEnd) ENTER();
   204→        LOGI(ANSI_COLOR_LIGHTCYAN "  // Object instance fields:\n" ANSI_COLOR_RESET);
   205→        needEnd = true;
   206→    }
   207→    super = clazz;
   208→    do {
   209→        if (!(options.show_flag & SHOW_FIELD))
   210→            break;
   211→
   212→        if (clazz != super) {
   213→            if (needEnd) ENTER();
   214→            LOGI(ANSI_COLOR_LIGHTCYAN "  // extends %s\n" ANSI_COLOR_RESET, super.PrettyDescriptor().c_str());
   215→            needEnd = true;
   216→        }
   217→
   218→        auto callback = [&](art::ArtField& field) -> bool {
   219→            fields.push_back(field);
   220→            return false;
   221→        };
   222→        Android::ForeachInstanceField(super, callback);
   223→        std::sort(fields.begin(), fields.end(), art::ArtField::Compare);
   224→        for (auto& field : fields) {
   225→            LOGI(format.c_str(), field.offset(), art::PrettyFieldAccessFlags(field.access_flags()).c_str(),
   226→                                 field.PrettyTypeDescriptor().c_str(), field.GetName());
   227→        }
   228→        fields.clear();
   229→
   230→        super = super.GetSuperClass();
   231→    } while (super.Ptr());
   232→
   233→    if (clazz.NumMethods() && (options.show_flag & SHOW_METHOD)) {
   234→        if (needEnd) ENTER();
   235→        LOGI(ANSI_COLOR_LIGHTCYAN "  // Methods:\n" ANSI_COLOR_RESET);
   236→        needEnd = true;
   237→    }
   238→    auto print_method = [](art::ArtMethod& method) -> bool {
   239→        LOGI("    [0x%" PRIx64 "] " ANSI_COLOR_LIGHTGREEN "%s" ANSI_COLOR_RESET "%s\n",
   240→                method.Ptr(), art::PrettyMethodAccessFlags(method.access_flags()).c_str(), method.ColorPrettyMethod().c_str());
   241→        return false;
   242→    };
   243→    if ((options.show_flag & SHOW_METHOD)) Android::ForeachArtMethods(current, print_method);
   244→
   245→    LOGI("}\n");
