    29→
    30→void JavaVerify::init(int opt, int flag) {
    31→    options = opt;
    32→    flags = flag;
    33→}
    34→
    35→void JavaVerify::verify(art::mirror::Object& object) {
    36→    art::mirror::Class clazz = object.GetClass();
    37→
    38→    if (options & CHECK_FULL_BAD_OBJECT) {
    39→        if (object.IsClass()) {
    40→            art::mirror::Class thiz = object;
    41→            VerifyClassObject(thiz);
    42→        } else if (clazz.IsArrayClass()) {
    43→            art::mirror::Array thiz = object;
    44→            VerifyArrayObject(thiz);
    45→        } else {
    46→            VerifyInstanceObject(object);
    47→        }
    48→    }
    49→
    50→    if (options & CHECK_FULL_CONFLICT_METHOD) {
    51→        if (object.IsClass()) {
    52→            art::mirror::Class thiz = object;
    53→            VerifyConflictMethod(thiz);
    54→        }
    55→    }
    56→
    57→    if (options & CHECK_FULL_REUSE_DEX_PC_PTR) {
    58→        if (object.IsClass()) {
    59→            art::mirror::Class thiz = object;
    60→            VerifyReuseDexPcMethod(thiz);
    61→        }
    62→    }
    63→
    64→    if ((options & CHECK_FULL_U_EXTENDS_RECORD)
    65→            && (Android::Sdk() == Android::U)) {
    66→        if (object.IsClass()) {
    67→            art::mirror::Class thiz = object;
    68→            VerifyRecordClass(thiz);
    69→        }
    70→    }
    71→}
    72→
    73→void JavaVerify::VerifyClassObject(art::mirror::Class& clazz) {
    74→    art::mirror::Class current = clazz;
    75→    std::string format = PrintCommand::FormatSize(clazz.SizeOf());
    76→    PrintCommand::Options options;
    77→    bool need_header = true;
    78→
    79→    std::vector<art::ArtField> fields;
    80→    auto callback = [&](art::ArtField& field) -> bool {
    81→        fields.push_back(field);
    82→        return false;
    83→    };
    84→
    85→    Android::ForeachStaticField(current, callback);
    86→    current = clazz.GetClass();
    87→    if (current.Ptr() && current.IsValid()) {
    88→        Android::ForeachInstanceField(current, callback);
    89→        current = current.GetSuperClass();
    90→
    91→        if (current.Ptr() && current.IsValid())
    92→            Android::ForeachInstanceField(current, callback);
    93→    }
    94→    std::sort(fields.begin(), fields.end(), art::ArtField::Compare);
    95→
    96→    for (auto& field : fields) {
    97→        uint64_t size;
    98→        const char* sig = field.GetTypeDescriptor();
    99→        Android::BasicType type = Android::SignatureToBasicTypeAndSize(sig, &size, "B");
   100→        if (type != Android::basic_object)
   101→            continue;
   102→
   103→        art::mirror::Object tmp(field.GetObj(clazz), clazz);
   104→        if (tmp.Ptr() && !tmp.IsValid()) {
   105→            if (need_header) {
   106→                LOGE("verify class: " ANSI_COLOR_LIGHTYELLOW "[0x%" PRIx64 "]\n" ANSI_COLOR_RESET, clazz.Ptr());
   107→                LOGI("Class Name: " ANSI_COLOR_LIGHTMAGENTA "%s\n" ANSI_COLOR_RESET, clazz.PrettyDescriptor().c_str());
   108→                need_header = false;
   109→            }
   110→            PrintCommand::PrintField(format.c_str(), current, clazz, field, options);
   111→        }
   112→    }
   113→    if (!need_header) ENTER();
   114→}
   115→
   116→void JavaVerify::VerifyArrayObject(art::mirror::Array& array) {
   117→    art::mirror::Class clazz = array.GetClass();
   118→    uint32_t length = array.GetLength();
   119→    bool need_header = true;
   120→
   121→    if (array.IsObjectArray()) {
   122→        for (int32_t i = 0; i < length; ++i) {
   123→            api::MemoryRef ref(array.GetRawData(sizeof(uint32_t), i), array);
   124→            art::mirror::Object object(*reinterpret_cast<uint32_t *>(ref.Real()), array);
   125→            if (object.Ptr() && !object.IsValid()) {
   126→                if (need_header) {
   127→                    LOGE("verify array: " ANSI_COLOR_LIGHTYELLOW "[0x%" PRIx64 "]\n" ANSI_COLOR_RESET, array.Ptr());
   128→                    LOGI("Array Name: " ANSI_COLOR_LIGHTMAGENTA "%s\n" ANSI_COLOR_RESET, clazz.PrettyDescriptor().c_str());
   129→                    need_header = false;
   130→                }
   131→                LOGI("    [%d] " ANSI_COLOR_LIGHTMAGENTA "0x%" PRIx64 "\n" ANSI_COLOR_RESET, i, object.Ptr());
   132→            }
   133→        }
   134→    }
   135→    if (!need_header) ENTER();
   136→}
   137→
   138→void JavaVerify::VerifyInstanceObject(art::mirror::Object& object) {
   139→    art::mirror::Class clazz = object.GetClass();
   140→    art::mirror::Class super = clazz;
   141→    std::string format = PrintCommand::FormatSize(object.SizeOf());
   142→    PrintCommand::Options options;
   143→    bool need_header = true;
   144→    do {
   145→        std::vector<art::ArtField> fields;
   146→        auto callback = [&](art::ArtField& field) -> bool {
   147→            fields.push_back(field);
   148→            return false;
   149→        };
   150→        Android::ForeachInstanceField(super, callback);
   151→        std::sort(fields.begin(), fields.end(), art::ArtField::Compare);
   152→
   153→        for (auto& field : fields) {
   154→            uint64_t size;
   155→            const char* sig = field.GetTypeDescriptor();
   156→            Android::BasicType type = Android::SignatureToBasicTypeAndSize(sig, &size, "B");
   157→            if (type != Android::basic_object)
   158→                continue;
   159→
   160→            art::mirror::Object tmp(field.GetObj(object), object);
   161→            if (tmp.Ptr() && !tmp.IsValid()) {
   162→                if (need_header) {
   163→                    LOGE("verify instance: " ANSI_COLOR_LIGHTYELLOW "[0x%" PRIx64 "]\n" ANSI_COLOR_RESET, object.Ptr());
   164→                    LOGI("Object Name: " ANSI_COLOR_LIGHTMAGENTA "%s\n" ANSI_COLOR_RESET, clazz.PrettyDescriptor().c_str());
   165→                    need_header = false;
   166→                }
   167→                PrintCommand::PrintField(format.c_str(), super, object, field, options);
   168→            }
   169→        }
   170→
   171→        super = super.GetSuperClass();
   172→    } while (super.Ptr());
   173→    if (!need_header) ENTER();
   174→}
   175→
   176→void JavaVerify::VerifyConflictMethod(art::mirror::Class& clazz) {
   177→    ClassCommand::Options options = {
   178→        .show_flag = ClassCommand::SHOW_IMPL,
   179→    };
   180→    bool need_header = true;
   181→    auto print_method = [&](art::ArtMethod& method) -> bool {
   182→        if (!method.IsDefaultConflicting())
   183→            return false;
   184→
   185→        if (need_header) {
   186→            LOGE("verify class conflict method\n");
   187→            ClassCommand::PrintPrettyClassContent(clazz, options);
   188→            need_header = false;
   189→        }
   190→        LOGI("[0x%" PRIx64 "] " ANSI_COLOR_LIGHTGREEN "%s" ANSI_COLOR_RESET "%s\n",
   191→                method.Ptr(), art::PrettyMethodAccessFlags(method.access_flags()).c_str(), method.ColorPrettyMethod().c_str());
   192→        return false;
   193→    };
   194→    Android::ForeachArtMethods(clazz, print_method);
   195→}
   196→
   197→void JavaVerify::VerifyReuseDexPcMethod(art::mirror::Class& clazz) {
   198→    auto has_code_method = [&](art::ArtMethod& method) -> bool {
   199→        if (!method.HasCodeItem())
   200→            return false;
   201→
   202→        if (method.IsDefaultConflicting())
   203→            return false;
   204→
   205→        art::dex::CodeItem item = method.GetCodeItem();
   206→        if (!item.Ptr())
   207→            return false;
   208→
   209→        methods.insert(std::pair<uint64_t, uint64_t>(method.Ptr(), item.Ptr() + item.code_offset_));
   210→        return false;
   211→    };
   212→    Android::ForeachArtMethods(clazz, has_code_method);
   213→}
   214→
