    37→
    38→int Opencore::Dump(int argc, char* const argv[]) {
    39→    int opt;
    40→    int option_index = 0;
    41→    optind = 0; // reset
    42→    static struct option long_options[] = {
    43→        {"pid",     required_argument, 0, 'p'},
    44→        {"filter",  required_argument, 0, 'f'},
    45→        {"dir",     required_argument, 0, 'd'},
    46→        {"output",  required_argument, 0, 'o'},
    47→        {"machine", required_argument, 0, 'm'},
    48→        {0,         0,                 0,  0 },
    49→    };
    50→
    51→    int pid = 0;
    52→    if (CoreApi::IsRemote())
    53→        pid = Env::CurrentRemotePid();
    54→    int filter = FILTER_SPECIAL_VMA
    55→               | FILTER_SANITIZER_SHADOW_VMA
    56→               | FILTER_NON_READ_VMA;
    57→    char* dir = const_cast<char *>(Env::CurrentDir());
    58→    char* filename = nullptr;
    59→    char* machine = const_cast<char *>(NONE_MACHINE);
    60→    while ((opt = getopt_long(argc, argv, "p:f:d:o:m:",
    61→                long_options, &option_index)) != -1) {
    62→        switch (opt) {
    63→            case 'p':
    64→                pid = std::atoi(optarg);
    65→                break;
    66→            case 'f':
    67→                filter = Utils::atol(optarg);
    68→                break;
    69→            case 'd':
    70→                dir = optarg;
    71→                break;
    72→            case 'o':
    73→                filename = optarg;
    74→                break;
    75→            case 'm':
    76→                machine = optarg;
    77→                break;
    78→        }
    79→    }
    80→
    81→    std::string type = machine ? machine : "";
    82→    if (!strcmp(machine, NONE_MACHINE)) {
    83→        type = DecodeMachine(pid);
    84→    }
    85→
    86→    std::unique_ptr<Opencore> impl = Opencore::MakeArch(type);
    87→    if (impl) {
    88→        impl->setDir(dir);
    89→        impl->setPid(pid);
    90→        impl->setTid(pid);
    91→        impl->setFilter(filter);
    92→        impl->Coredump(filename);
    93→    }
    94→    return 0;
    95→}
    96→
    97→std::unique_ptr<Opencore> Opencore::MakeArch(std::string& type) {
    98→    std::unique_ptr<Opencore> impl;
    99→#if defined(__LP64__)
   100→    if (type == "arm64" || type == "ARM64") {
   101→        impl = std::make_unique<arm64::Opencore>();
   102→    } else if (type == "x86_64" || type == "X86_64") {
   103→        impl = std::make_unique<x86_64::Opencore>();
   104→    } else if (type == "riscv64" || type == "RISCV64") {
   105→        impl = std::make_unique<riscv64::Opencore>();
   106→    } else if (type == "arm" || type == "ARM") {
   107→        impl = std::make_unique<arm::Opencore>();
   108→    } else if (type == "x86" || type == "X86") {
   109→        impl = std::make_unique<x86::Opencore>();
   110→    }
   111→#else
   112→    if (type == "arm" || type == "ARM") {
   113→        impl = std::make_unique<arm::Opencore>();
   114→    } else if (type == "x86" || type == "X86") {
   115→        impl = std::make_unique<x86::Opencore>();
   116→    }
   117→#endif
   118→    return std::move(impl);
   119→}
   120→
   121→bool Opencore::Coredump(const char* filename) {
   122→    int ori_dumpable;
   123→    int flag, pid, tid;
   124→    char comm[16];
   125→    bool need_split = false;
   126→    bool need_restore_dumpable = false;
   127→    bool need_restore_ptrace = false;
   128→    std::string output;
   129→
   130→    pid = getPid();
   131→    tid = getTid();
   132→    flag = getFlag();
   133→
   134→    if (getDir().length() > 0) {
   135→        output.append(getDir()).append("/");
   136→    }
   137→    if (!filename) {
   138→        if (!(flag & FLAG_ALL)) {
   139→            flag |= FLAG_CORE;
   140→            flag |= FLAG_TID;
   141→        }
   142→
   143→        if (flag & FLAG_CORE)
   144→            output.append("core.");
   145→
   146→        if (flag & FLAG_PROCESS_COMM) {
   147→            char comm_path[32];
   148→            snprintf(comm_path, sizeof(comm_path), "/proc/%d/comm", pid);
   149→            int fd = open(comm_path, O_RDONLY);
   150→            if (fd > 0) {
   151→                memset(&comm, 0x0, sizeof(comm));
   152→                int rc = read(fd, &comm, sizeof(comm) - 1);
   153→                if (rc > 0) {
   154→                    for (int i = 0; i < rc; i++) {
   155→                        if (comm[i] == '\n') {
   156→                            comm[i] = 0;
   157→                            break;
   158→                        }
   159→                    }
   160→                    comm[rc] = 0;
   161→                    output.append(comm);
   162→                } else {
   163→                    output.append("unknown");
   164→                }
   165→                close(fd);
   166→            }
   167→            need_split = true;
   168→        }
   169→
   170→        if (flag & FLAG_PID) {
   171→            if (need_split)
   172→                output.append("_");
   173→            output.append(std::to_string(pid));
   174→            need_split = true;
   175→        }
   176→
   177→        if (flag & FLAG_THREAD_COMM) {
   178→            if (need_split)
   179→                output.append("_");
   180→
   181→            char thread_comm_path[64];
   182→            snprintf(thread_comm_path, sizeof(thread_comm_path), "/proc/%d/task/%d/comm", pid, tid);
   183→            int fd = open(thread_comm_path, O_RDONLY);
   184→            if (fd > 0) {
   185→                memset(&comm, 0x0, sizeof(comm));
   186→                int rc = read(fd, &comm, sizeof(comm) - 1);
   187→                if (rc > 0) {
   188→                    for (int i = 0; i < rc; i++) {
   189→                        if (comm[i] == '\n') {
   190→                            comm[i] = 0;
   191→                            break;
   192→                        }
   193→                    }
   194→                    comm[rc] = 0;
   195→                    output.append(comm);
   196→                } else {
   197→                    output.append("unknown");
   198→                }
   199→                close(fd);
   200→            }
   201→            need_split = true;
   202→        }
   203→
   204→        if (flag & FLAG_TID) {
   205→            if (need_split)
   206→                output.append("_");
   207→            output.append(std::to_string(tid));
   208→            need_split = true;
   209→        }
   210→
   211→        if (flag & FLAG_TIMESTAMP) {
   212→            struct timeval tv;
   213→            gettimeofday(&tv, NULL);
   214→            if (need_split)
   215→                output.append("_");
   216→            output.append(std::to_string(tv.tv_sec));
   217→        }
   218→    } else {
   219→        output.append(filename);
   220→    }
   221→
   222→    ori_dumpable = prctl(PR_GET_DUMPABLE);
   223→    if (!prctl(PR_SET_DUMPABLE, 1))
   224→        need_restore_dumpable = true;
   225→
   226→    if (!prctl(PR_SET_PTRACER, PR_SET_PTRACER_ANY))
   227→        need_restore_ptrace = true;
   228→
   229→    bool ret = DoCoredump(output.c_str());
   230→
   231→    if (need_restore_dumpable) prctl(PR_SET_DUMPABLE, ori_dumpable);
   232→    if (need_restore_ptrace) prctl(PR_SET_PTRACER, 0);
   233→
   234→    return ret;
   235→}
   236→
   237→Opencore::~Opencore() {
   238→    Continue();
   239→    maps.clear();
   240→}
   241→
   242→int Opencore::IsFilterSegment(Opencore::VirtualMemoryArea& vma) {
   243→    int filter = getFilter();
   244→    if (filter & FILTER_SPECIAL_VMA) {
   245→        if (vma.file == "/dev/binderfs/hwbinder"
   246→                || vma.file == "/dev/binderfs/binder"
   247→                || vma.file == "[vvar]"
   248→                || vma.file == "/dev/mali0"
   249→           ) {
   250→            return VMA_NULL;
   251→        }
   252→    }
   253→
   254→    if (filter & FILTER_FILE_VMA) {
   255→        if (vma.inode > 0 && vma.flags[1] == '-')
   256→            return NeedFilterFile(vma);
   257→    }
   258→
   259→    if (filter & FILTER_SHARED_VMA) {
   260→        if (vma.flags[3] == 's' || vma.flags[3] == 'S')
   261→            return VMA_NULL;
   262→    }
   263→
   264→    if (filter & FILTER_SANITIZER_SHADOW_VMA) {
   265→        if (vma.file == "[anon:low shadow]"
   266→                || vma.file == "[anon:high shadow]"
   267→                || (vma.file.compare(0, 12, "[anon:hwasan") == 0))
   268→            return VMA_NULL;
   269→    }
   270→
   271→    if (filter & FILTER_NON_READ_VMA) {
