int Opencore::Dump(int argc, char* const argv[]) {
    int opt;
    int option_index = 0;
    optind = 0; // reset
    static struct option long_options[] = {
        {"pid",     required_argument, 0, 'p'},
        {"filter",  required_argument, 0, 'f'},
        {"dir",     required_argument, 0, 'd'},
        {"output",  required_argument, 0, 'o'},
        {"machine", required_argument, 0, 'm'},
        {0,         0,                 0,  0 },
    };

    int pid = 0;
    if (CoreApi::IsRemote())
        pid = Env::CurrentRemotePid();
    int filter = FILTER_SPECIAL_VMA
               | FILTER_SANITIZER_SHADOW_VMA
               | FILTER_NON_READ_VMA;
    char* dir = const_cast<char *>(Env::CurrentDir());
    char* filename = nullptr;
    char* machine = const_cast<char *>(NONE_MACHINE);
    while ((opt = getopt_long(argc, argv, "p:f:d:o:m:",
                long_options, &option_index)) != -1) {
        switch (opt) {
            case 'p':
                pid = std::atoi(optarg);
                break;
            case 'f':
                filter = Utils::atol(optarg);
                break;
            case 'd':
                dir = optarg;
                break;
            case 'o':
                filename = optarg;
                break;
            case 'm':
                machine = optarg;
                break;
        }
    }

    std::string type = machine ? machine : "";
    if (!strcmp(machine, NONE_MACHINE)) {
        type = DecodeMachine(pid);
    }

    std::unique_ptr<Opencore> impl = Opencore::MakeArch(type);
    if (impl) {
        impl->setDir(dir);
        impl->setPid(pid);
        impl->setTid(pid);
        impl->setFilter(filter);
        impl->Coredump(filename);
    }
    return 0;
}

std::unique_ptr<Opencore> Opencore::MakeArch(std::string& type) {
    std::unique_ptr<Opencore> impl;
#if defined(__LP64__)
    if (type == "arm64" || type == "ARM64") {
        impl = std::make_unique<arm64::Opencore>();
    } else if (type == "x86_64" || type == "X86_64") {
        impl = std::make_unique<x86_64::Opencore>();
    } else if (type == "riscv64" || type == "RISCV64") {
        impl = std::make_unique<riscv64::Opencore>();
    } else if (type == "arm" || type == "ARM") {
        impl = std::make_unique<arm::Opencore>();
    } else if (type == "x86" || type == "X86") {
        impl = std::make_unique<x86::Opencore>();
    }
#else
    if (type == "arm" || type == "ARM") {
        impl = std::make_unique<arm::Opencore>();
    } else if (type == "x86" || type == "X86") {
        impl = std::make_unique<x86::Opencore>();
    }
#endif
    return std::move(impl);
}

bool Opencore::Coredump(const char* filename) {
    int ori_dumpable;
    int flag, pid, tid;
    char comm[16];
    bool need_split = false;
    bool need_restore_dumpable = false;
    bool need_restore_ptrace = false;
    std::string output;

    pid = getPid();
    tid = getTid();
    flag = getFlag();

    if (getDir().length() > 0) {
        output.append(getDir()).append("/");
    }
    if (!filename) {
        if (!(flag & FLAG_ALL)) {
            flag |= FLAG_CORE;
            flag |= FLAG_TID;
        }

        if (flag & FLAG_CORE)
            output.append("core.");

        if (flag & FLAG_PROCESS_COMM) {
            char comm_path[32];
            snprintf(comm_path, sizeof(comm_path), "/proc/%d/comm", pid);
            int fd = open(comm_path, O_RDONLY);
            if (fd > 0) {
                memset(&comm, 0x0, sizeof(comm));
                int rc = read(fd, &comm, sizeof(comm) - 1);
                if (rc > 0) {
                    for (int i = 0; i < rc; i++) {
                        if (comm[i] == '\n') {
                            comm[i] = 0;
                            break;
                        }
                    }
                    comm[rc] = 0;
                    output.append(comm);
                } else {
                    output.append("unknown");
                }
                close(fd);
            }
            need_split = true;
        }

        if (flag & FLAG_PID) {
            if (need_split)
                output.append("_");
            output.append(std::to_string(pid));
            need_split = true;
        }

        if (flag & FLAG_THREAD_COMM) {
            if (need_split)
                output.append("_");

            char thread_comm_path[64];
            snprintf(thread_comm_path, sizeof(thread_comm_path), "/proc/%d/task/%d/comm", pid, tid);
            int fd = open(thread_comm_path, O_RDONLY);
            if (fd > 0) {
                memset(&comm, 0x0, sizeof(comm));
                int rc = read(fd, &comm, sizeof(comm) - 1);
                if (rc > 0) {
                    for (int i = 0; i < rc; i++) {
                        if (comm[i] == '\n') {
                            comm[i] = 0;
                            break;
                        }
                    }
                    comm[rc] = 0;
                    output.append(comm);
                } else {
                    output.append("unknown");
                }
                close(fd);
            }
            need_split = true;
        }

        if (flag & FLAG_TID) {
            if (need_split)
                output.append("_");
            output.append(std::to_string(tid));
            need_split = true;
        }

        if (flag & FLAG_TIMESTAMP) {
            struct timeval tv;
            gettimeofday(&tv, NULL);
            if (need_split)
                output.append("_");
            output.append(std::to_string(tv.tv_sec));
        }
    } else {
        output.append(filename);
    }

    ori_dumpable = prctl(PR_GET_DUMPABLE);
    if (!prctl(PR_SET_DUMPABLE, 1))
        need_restore_dumpable = true;

    if (!prctl(PR_SET_PTRACER, PR_SET_PTRACER_ANY))
        need_restore_ptrace = true;

    bool ret = DoCoredump(output.c_str());

    if (need_restore_dumpable) prctl(PR_SET_DUMPABLE, ori_dumpable);
    if (need_restore_ptrace) prctl(PR_SET_PTRACER, 0);

    return ret;
}

Opencore::~Opencore() {
    Continue();
    maps.clear();
}

int Opencore::IsFilterSegment(Opencore::VirtualMemoryArea& vma) {
    int filter = getFilter();
    if (filter & FILTER_SPECIAL_VMA) {
        if (vma.file == "/dev/binderfs/hwbinder"
                || vma.file == "/dev/binderfs/binder"
                || vma.file == "[vvar]"
                || vma.file == "/dev/mali0"
           ) {
            return VMA_NULL;
        }
    }

    if (filter & FILTER_FILE_VMA) {
        if (vma.inode > 0 && vma.flags[1] == '-')
            return NeedFilterFile(vma);
    }

    if (filter & FILTER_SHARED_VMA) {
        if (vma.flags[3] == 's' || vma.flags[3] == 'S')
            return VMA_NULL;
    }

    if (filter & FILTER_SANITIZER_SHADOW_VMA) {
        if (vma.file == "[anon:low shadow]"
                || vma.file == "[anon:high shadow]"
                || (vma.file.compare(0, 12, "[anon:hwasan") == 0))
            return VMA_NULL;
    }

    if (filter & FILTER_NON_READ_VMA) {
        if (vma.flags[0] == '-' && vma.flags[1] == '-' && vma.flags[2] == '-')
            return VMA_NULL;
    }

    if (filter & FILTER_JAVAHEAP_VMA) {
        if (vma.file.compare(0, 12, "[anon:dalvik") == 0)
            return VMA_NULL;
    }

    if (filter & FILTER_JIT_CACHE_VMA) {
        if (vma.file.compare(0, 10, "/memfd:jit") == 0)
            return VMA_NULL;
    }
    return VMA_NORMAL;
}

void Opencore::StopTheWorld(int pid) {
    char task_dir[32];
    struct dirent *entry;
    snprintf(task_dir, sizeof(task_dir), "/proc/%d/task", pid);
    DIR *dp = opendir(task_dir);
    if (dp) {
        while ((entry=readdir(dp)) != NULL) {
            if (!strncmp(entry->d_name, ".", 1)) {
                continue;
            }

            pid_t tid = std::atoi(entry->d_name);
            Opencore::StopTheThread(tid);
        }
        closedir(dp);
    }
}

bool Opencore::StopTheThread(int tid) {
    ThreadRecord ts = {
        .pid = tid,
        .attached = false,
    };
    if (ptrace(PTRACE_ATTACH, tid, NULL, 0) < 0) {
        LOGD("%s %d: %s\n", __func__ , tid, strerror(errno));
        threads.push_back(ts);
        return false;
    }

    ts.attached = true;
    threads.push_back(ts);

    int status = 0;
    int result = waitpid(tid, &status, WUNTRACED | __WALL);
    if (result != tid) {
        LOGW("waitpid failed on %d while detaching\n", tid);
        return false;
    }
    if (WIFSTOPPED(status)) {
        int received_signal = 0;
        if (status >> 16 == PTRACE_EVENT_STOP) {
            received_signal = 0;
        } else {
            received_signal = WSTOPSIG(status);
        }
        LOGD("waitpid on %d, status 0x%x received_signal %d\n", tid, status, received_signal);
        return true;
    }
    LOGW("waitpid failed on %d while non-stop, status 0x%x\n", tid, status);
    return false;
}

void Opencore::Continue() {
    for (int index = 0; index < threads.size(); index++) {
        ThreadRecord& ts = threads[index];
        if (!ts.attached)
            continue;

        pid_t tid = ts.pid;
        if (ptrace(PTRACE_DETACH, tid, NULL, 0) < 0) {
            LOGD("%s %d: %s\n", __func__ , tid, strerror(errno));
            continue;
        }
    }
    threads.clear();
}

bool Opencore::IsBit64(int pid) {
    char filename[32];
    lp64::Auxv vec[32];
    snprintf(filename, sizeof(filename), "/proc/%d/auxv", pid);

    FILE *fp = fopen(filename, "rb");
    if (fp != nullptr) {
        fread(&vec, sizeof(vec), 1, fp);
        fclose(fp);
    }

    for (int index = 0; index < 32; ++index) {
        if (vec[index].type == AT_PHENT
                && vec[index].value == sizeof(Elf64_Phdr))
            return true;
        if (!vec[index].type)
            break;
    }
    return false;
}

std::string Opencore::DecodeMachine(int pid) {
    struct utsname buf;
    if (!uname(&buf)) {
#if defined(__LP64__)
        if (!strcmp(buf.machine, X86_64_MACHINE)) {
            if (IsBit64(pid)) {
                return X86_64_MACHINE;
            } else {
                return X86_MACHINE;
            }
        } else if (!strcmp(buf.machine, AARCH64_MACHINE)
                || !strcmp(buf.machine, ARM64_MACHINE)) {
            if (IsBit64(pid)) {
                return ARM64_MACHINE;
            } else {
                return ARM_MACHINE;
            }
        } else {
            LOGE("Not support machine %s\n", buf.machine);
        }
#else
        if (!strcmp(buf.machine, I686_MACHINE)
                || !strcmp(buf.machine, I386_MACHINE)
                || !strcmp(buf.machine, X86_MACHINE)) {
            if (!IsBit64(pid))
                return X86_MACHINE;
            else
                LOGW("Not support target process 64 bits\n");
        } else if (!strcmp(buf.machine, ARM_MACHINE)
                || !strcmp(buf.machine, V7L_MACHINE)
                || !strcmp(buf.machine, V8L_MACHINE)
                || !strcmp(buf.machine, ARMV7L_MACHINE)
                || !strcmp(buf.machine, ARMV8L_MACHINE)) {
            if (!IsBit64(pid))
                return ARM_MACHINE;
            else
                LOGW("Not support target process 64 bits\n");
        } else {
            LOGE("Not support machine %s\n", buf.machine);
        }
#endif
    } else {
        LOGE("uname fail!\n");
    }
    return NONE_MACHINE;
}

void Opencore::TermStopHandle(int signal) {
    struct utsname buf;
    int major = 0;
    if (!uname(&buf)) {
        sscanf(buf.release, "%d.%*d.%*d+", &major);
        if (major >= 4)
            _exit(0);
        // other do nothing
    }
}

bool Opencore::isAlive(int pid) {
    if (pid <= 0) {
        return false;
    }

    if (kill(pid, 0) == -1) {
        if (errno == ESRCH) {
            return false;
        } else if (errno == EPERM) {
            return true;
        }
        return false;
    }
    return true;
}

void Opencore::ParseMaps(int pid, std::vector<VirtualMemoryArea>& maps) {
    char filename[32];
    char line[1024];

    snprintf(filename, sizeof(filename), "/proc/%d/maps", pid);
    FILE *fp = fopen(filename, "r");
    if (fp) {
        bool compat32 = !IsBit64(pid);
        while (fgets(line, sizeof(line), fp)) {
            int m;
            VirtualMemoryArea vma;
            char filename[256] = {'\0'};

            sscanf(line, "%" PRIx64 "-%" PRIx64 " %c%c%c%c %x %x:%x  %" PRIu64 "  %[^\n] %n",
                   &vma.begin, &vma.end,
                   &vma.flags[0], &vma.flags[1], &vma.flags[2], &vma.flags[3],
                   &vma.offset, &vma.major, &vma.minor, &vma.inode, filename, &m);

            vma.file = filename;

            // avoid compat32 bit application dump64
            if (compat32 && vma.begin > 0xFFFFFFFF)
                break;
            maps.push_back(vma);
        }
        fclose(fp);
    }
}

void Opencore::Usage() {
    LOGI("Usage: remote core [-p <PID>] [-m <MACHINE>] [OPTION...]\n");
    LOGI("Option:\n");
    LOGI("    -p, --pid <PID>           set target pid\n");
    LOGI("    -d, --dir <DIR>           set target dir\n");
    LOGI("    -m, --machine <Machine>   set target machine\n");
    LOGI("Machine:\n");
    LOGI("     { arm64, arm, x86_64, x86, riscv64 }\n");
    LOGI("    -o, --output <COREFILE>   set coredump filename\n");
    LOGI("    -f, --filter <Filter>     set coredump ignore filter\n");
    LOGI("Filter: (0x19 default)\n");
    LOGI("     0x001: filter-special-vma (default)\n");
    LOGI("     0x002: filter-file-vma\n");
    LOGI("     0x004: filter-shared-vma\n");
    LOGI("     0x008: filter-sanitizer-shadow-vma (default)\n");
    LOGI("     0x010: filter-non-read-vma (default)\n");
    LOGI("     0x020: filter-signal-context (unused)\n");
    LOGI("     0x040: filter-minidump\n");
    LOGI("     0x080: filter-javaheap-vma\n");
    LOGI("     0x100: filter-jit-cache-vma\n");
    ENTER();
    LOGI("core-parser> remote core -p 1 -m x86_64 -d /data -f 0x18\n");
    LOGI("Coredump /data/core.init_1_1718900269 ...\n");
    LOGI("Finish done.\n");
    LOGI("core-parser> core /data/core.init_1_1718900269\n");
    LOGI("Core load (0x7256f0c21090) /data/core.init_1_1718900269\n");
    LOGI("Core env: /data/core.init_1_1718900269\n");
    LOGI("  * Machine: x86_64\n");
    LOGI("  * Bits: 64\n");
    LOGI("  * PointSize: 8\n");
    LOGI("  * PointMask: 0xffffffffffffffff\n");
    LOGI("  * VabitsMask: 0xffffffffffffffff\n");
    LOGI("  * Thread: 1\n");
    LOGI("  ...\n");
}

