    30→void OpencoreImpl::ParserPhdr(int index, Opencore::VirtualMemoryArea& vma) {
    31→    phdr[index].p_type = PT_LOAD;
    32→
    33→    phdr[index].p_vaddr = (Elf64_Addr)vma.begin;
    34→    phdr[index].p_paddr = 0x0;
    35→    phdr[index].p_memsz = (Elf64_Addr)vma.end-(Elf64_Addr)vma.begin;
    36→
    37→    if (vma.flags[0] == 'r' || vma.flags[0] == 'R')
    38→        phdr[index].p_flags = phdr[index].p_flags | PF_R;
    39→
    40→    if (vma.flags[1] == 'w' || vma.flags[1] == 'W')
    41→        phdr[index].p_flags = phdr[index].p_flags | PF_W;
    42→
    43→    if (vma.flags[2] == 'x' || vma.flags[2] == 'X')
    44→        phdr[index].p_flags = phdr[index].p_flags | PF_X;
    45→
    46→    phdr[index].p_filesz = phdr[index].p_memsz;
    47→    phdr[index].p_align = align_size;
    48→}
    49→
    50→void OpencoreImpl::ParserNtFile(int index, Opencore::VirtualMemoryArea& vma) {
    51→    file[index].begin = (Elf64_Addr)vma.begin;
    52→    file[index].end = (Elf64_Addr)vma.end;
    53→    file[index].offset = vma.offset >> 12;
    54→    fileslen += vma.file.length() + 1;
    55→}
    56→
    57→void OpencoreImpl::ParseProcessMapsVma(int pid) {
    58→    ParseMaps(pid, maps);
    59→    if (!maps.size())
    60→        return;
    61→
    62→    phdr.assign(maps.size(), {});
    63→    file.assign(maps.size(), {});
    64→
    65→    for (int index = 0; index < maps.size(); ++index) {
    66→        Opencore::VirtualMemoryArea& vma = maps[index];
    67→        ParserPhdr(index, vma);
    68→        ParserNtFile(index, vma);
    69→    }
    70→}
    71→
    72→void OpencoreImpl::CreateCoreHeader() {
    73→    snprintf((char *)ehdr.e_ident, 5, ELFMAG);
    74→    ehdr.e_ident[EI_CLASS] = ELFCLASS64;
    75→    ehdr.e_ident[EI_DATA] = ELFDATA2LSB;
    76→    ehdr.e_ident[EI_VERSION] = EV_CURRENT;
    77→
    78→    ehdr.e_type = ET_CORE;
    79→    ehdr.e_machine = getMachine();
    80→    ehdr.e_version = EV_CURRENT;
    81→    ehdr.e_entry = 0x0;
    82→    ehdr.e_phoff = sizeof(Elf64_Ehdr);
    83→    ehdr.e_shoff = 0x0;
    84→    ehdr.e_flags = 0x0;
    85→    ehdr.e_ehsize = sizeof(Elf64_Ehdr);
    86→    ehdr.e_phentsize = sizeof(Elf64_Phdr);
    87→    ehdr.e_phnum = (int)phdr.size() + 1;
    88→    ehdr.e_shentsize = 0x0;
    89→    ehdr.e_shnum = 0x0;
    90→    ehdr.e_shstrndx = 0x0;
    91→}
    92→
    93→void OpencoreImpl::CreateCoreNoteHeader() {
    94→    note.p_type = PT_NOTE;
    95→    note.p_offset = sizeof(Elf64_Ehdr) + ehdr.e_phnum * sizeof(Elf64_Phdr);
    96→}
    97→
    98→void OpencoreImpl::CreateCoreAUXV(int pid) {
    99→    char filename[32];
   100→    lp64::Auxv vec;
   101→    snprintf(filename, sizeof(filename), "/proc/%d/auxv", pid);
   102→
   103→    FILE *fp = fopen(filename, "rb");
   104→    if (fp != nullptr) {
   105→        while (fread(&vec, sizeof(vec), 1, fp)) {
   106→            auxvnum++;
   107→        }
   108→        fseek(fp, 0, SEEK_SET);
   109→
   110→        auxv.assign(auxvnum, {});
   111→
   112→        int index =0;
   113→        while (fread(&vec, sizeof(vec), 1, fp)) {
   114→            auxv[index].type = vec.type;
   115→            auxv[index].value = vec.value;
   116→            index++;
   117→        }
   118→
   119→        fclose(fp);
   120→    }
   121→}
