   123→void OpencoreImpl::SpecialCoreFilter() {
   124→    for (int index = 0; index < maps.size(); ++index) {
   125→        Opencore::VirtualMemoryArea& vma = maps[index];
   126→        int vma_flag = IsFilterSegment(vma) | IsSpecialFilterSegment(vma);
   127→        if (vma_flag & VMA_NULL)
   128→            phdr[index].p_filesz = 0x0;
   129→
   130→        if (vma_flag & VMA_INCLUDE)
   131→            phdr[index].p_filesz = phdr[index].p_memsz;
   132→    }
   133→}
   134→
   135→void OpencoreImpl::WriteCoreHeader(FILE* fp) {
   136→    fwrite((void *)&ehdr, sizeof(Elf64_Ehdr), 1, fp);
   137→}
   138→
   139→void OpencoreImpl::WriteCoreNoteHeader(FILE* fp) {
   140→    note.p_filesz += sizeof(lp64::Auxv) * auxvnum + sizeof(Elf64_Nhdr) + 8;
   141→    note.p_filesz += extra_note_filesz;
   142→    note.p_filesz += sizeof(lp64::File) * phdr.size() + sizeof(Elf64_Nhdr) + 8 + 2 * 8 + RoundUp(fileslen, 4);
   143→    fwrite((void *)&note, sizeof(Elf64_Phdr), 1, fp);
   144→}
   145→
   146→void OpencoreImpl::WriteCoreProgramHeaders(FILE* fp) {
   147→    if (phdr.empty())
   148→        return;
   149→
   150→    int phnum = (int)phdr.size();
   151→    uint64_t offset = RoundUp(note.p_offset + note.p_filesz, align_size);
   152→    phdr[0].p_offset = offset;
   153→    fwrite(&phdr[0], sizeof(Elf64_Phdr), 1, fp);
   154→
   155→    int index = 1;
   156→    while (index < phnum) {
   157→        phdr[index].p_offset = phdr[index - 1].p_offset + phdr[index-1].p_filesz;
   158→        fwrite(&phdr[index], sizeof(Elf64_Phdr), 1, fp);
   159→        index++;
   160→    }
   161→}
   162→
   163→void OpencoreImpl::WriteCoreAUXV(FILE* fp) {
   164→    Elf64_Nhdr elf_nhdr;
   165→    elf_nhdr.n_namesz = NOTE_CORE_NAME_SZ;
   166→    elf_nhdr.n_descsz = sizeof(lp64::Auxv) * auxvnum;
   167→    elf_nhdr.n_type = NT_AUXV;
   168→
   169→    char magic[8];
   170→    memset(magic, 0, sizeof(magic));
   171→    snprintf(magic, NOTE_CORE_NAME_SZ, ELFCOREMAGIC);
   172→
   173→    fwrite(&elf_nhdr, sizeof(Elf64_Nhdr), 1, fp);
   174→    fwrite(magic, sizeof(magic), 1, fp);
   175→
   176→    int index = 0;
   177→    while (index < auxvnum) {
   178→        fwrite(&auxv[index], sizeof(lp64::Auxv), 1, fp);
   179→        index++;
   180→    }
   181→}
   182→
   183→void OpencoreImpl::WriteNtFile(FILE* fp) {
   184→    int phnum = (int)phdr.size();
   185→    Elf64_Nhdr elf_nhdr;
   186→    elf_nhdr.n_namesz = NOTE_CORE_NAME_SZ;
   187→    elf_nhdr.n_descsz = sizeof(lp64::File) * phdr.size() + 2 * 8 + RoundUp(fileslen, 4);
   188→    elf_nhdr.n_type = NT_FILE;
   189→
   190→    char magic[8];
   191→    memset(magic, 0, sizeof(magic));
   192→    snprintf(magic, NOTE_CORE_NAME_SZ, ELFCOREMAGIC);
   193→
   194→    fwrite(&elf_nhdr, sizeof(Elf64_Nhdr), 1, fp);
   195→    fwrite(magic, sizeof(magic), 1, fp);
   196→
   197→    uint64_t number = phdr.size();
   198→    fwrite(&number, 8, 1, fp);
   199→    fwrite(&page_size, 8, 1, fp);
   200→
   201→    for (int index = 0; index < phnum; ++index)
   202→        fwrite(&file[index], sizeof(lp64::File), 1, fp);
   203→
   204→    for (int index = 0; index < phnum; ++index)
   205→        fwrite(maps[index].file.data(), maps[index].file.length() + 1, 1, fp);
   206→}
   207→
   208→void OpencoreImpl::AlignNoteSegment(FILE* fp) {
   209→    memset(zero.data(), 0x0, align_size);
   210→    uint64_t align_filesz = note.p_filesz - RoundUp(fileslen, 4) + fileslen;
   211→    uint64_t offset = RoundUp(note.p_offset + align_filesz, align_size);
   212→    uint64_t size = offset - (note.p_offset + align_filesz);
   213→    fwrite(zero.data(), size, 1, fp);
   214→}
   215→
   216→void OpencoreImpl::WriteCoreLoadSegment(int pid, FILE* fp) {
   217→    char filename[32];
   218→    int fd;
   219→    int index = 0;
   220→    int phnum = (int)phdr.size();
   221→    memset(zero.data(), 0x0, align_size);
   222→
   223→    snprintf(filename, sizeof(filename), "/proc/%d/mem", pid);
   224→    fd = open(filename, O_RDONLY);
   225→    if (fd < 0) {
   226→        LOGE("open %s fail.\n", filename);
   227→        return;
   228→    }
   229→
   230→    while(index < phnum) {
   231→        if (phdr[index].p_filesz > 0) {
   232→            long current_pos = ftell(fp);
   233→            bool need_padd_zero = false;
   234→            int count = phdr[index].p_memsz / align_size;
   235→            for (int i = 0; i < count; i++) {
   236→                memset(zero.data(), 0x0, align_size);
   237→                pread64(fd, zero.data(), phdr[index].p_align, phdr[index].p_vaddr + (i * align_size));
   238→                uint64_t ret = fwrite(zero.data(), align_size, 1, fp);
   239→                if (ret != 1) {
   240→                    LOGE("[%" PRIx64 "] write load segment fail. %s %s\n",
   241→                            (uint64_t)phdr[index].p_vaddr, strerror(errno), maps[index].file.c_str());
   242→                    if (errno == ENOSPC)
   243→                        return;
   244→
   245→                    need_padd_zero = true;
   246→                    break;
   247→                }
   248→            }
   249→            if (need_padd_zero && current_pos > 0) {
   250→                memset(zero.data(), 0x0, align_size);
   251→                fseek(fp, current_pos, SEEK_SET);
   252→                int count = phdr[index].p_memsz / align_size;
   253→                for (int i = 0; i < count; i++)
   254→                    fwrite(zero.data(), align_size, 1, fp);
   255→            }
   256→        }
   257→        index++;
   258→    }
   259→    close(fd);
   260→}
   261→
   262→bool OpencoreImpl::DoCoredump(const char* filename) {
   263→    Prepare(filename);
   264→
   265→    if (!Opencore::isAlive(getPid()))
   266→        return false;
   267→
   268→    FILE* fp = fopen(filename, "wb");
   269→    if (!fp) {
   270→        LOGE("%s %s: %s\n", __func__, filename, strerror(errno));
   271→        return false;
   272→    }
   273→
   274→    StopTheWorld(getPid());
   275→
   276→    ParseProcessMapsVma(getPid());
   277→    CreateCoreHeader();
   278→    CreateCoreNoteHeader();
   279→    CreateCorePrStatus(getPid());
   280→    CreateCoreAUXV(getPid());
   281→    SpecialCoreFilter();
   282→
   283→    // ELF Header
   284→    WriteCoreHeader(fp);
   285→
   286→    // Program Headers
   287→    WriteCoreNoteHeader(fp);
   288→    WriteCoreProgramHeaders(fp);
   289→
   290→    // Segments
   291→    WriteCorePrStatus(fp);
   292→    WriteCoreAUXV(fp);
   293→    WriteNtFile(fp);
   294→    AlignNoteSegment(fp);
   295→    WriteCoreLoadSegment(getPid(), fp);
   296→
   297→    fflush(fp);
   298→    fsync(fileno(fp));
   299→    fclose(fp);
   300→    return true;
   301→}
   302→
   303→int OpencoreImpl::NeedFilterFile(Opencore::VirtualMemoryArea& vma) {
   304→    std::unique_ptr<MemoryMap> map(MemoryMap::MmapFile(vma.file.c_str()));
   305→    if (!map) return VMA_NULL;
   306→
   307→    char* mem = (char*)map->data();
   308→    Elf64_Ehdr* ehdr = (Elf64_Ehdr*)mem;
   309→    if (strncmp(mem, ELFMAG, 4) || ehdr->e_machine != getMachine())
   310→        return VMA_NULL;
   311→
   312→    int ret = VMA_NULL;
   313→    Elf64_Phdr* phdr = (Elf64_Phdr *)(mem + sizeof(Elf64_Ehdr));
   314→    for (int index = 0; index < ehdr->e_phnum; index++) {
   315→        if (phdr[index].p_type != PT_LOAD)
   316→            continue;
   317→
   318→        int pos = RoundDown(phdr[index].p_offset, page_size);
   319→        int end = pos + phdr[index].p_memsz;
   320→        if (pos <= vma.offset && vma.offset < end) {
   321→            if ((phdr[index].p_flags & PF_W))
   322→                ret = VMA_NORMAL;
   323→        }
   324→    }
   325→    return ret;
   326→}
   327→
   328→uint64_t OpencoreImpl::FindAuxv(uint64_t type) {
   329→    for (int idx = 0; idx < auxvnum; ++idx) {
   330→        if (auxv[idx].type == type)
   331→            return auxv[idx].value;
   332→    }
   333→    return 0;
   334→}
   335→
   336→void OpencoreImpl::Prepare(const char* filename) {
   337→    LOGI("Coredump %s ...\n", filename);
   338→    zero.assign(align_size, 0);
   339→    memset(&ehdr, 0, sizeof(Elf64_Ehdr));
   340→    memset(&note, 0, sizeof(Elf64_Phdr));
   341→}
   342→
   343→OpencoreImpl::~OpencoreImpl() {
   344→    LOGI("Finish done.\n");
   345→}
   346→
   347→} // namespace lp64
