    59→    if (map) {
    60→        ElfHeader* header = reinterpret_cast<ElfHeader*>(map->data());
    61→        if (memcmp(header->ident, ELFMAG, 4)) {
    62→            LOGE("Invalid ELF file.\n");
    63→            return false;
    64→        }
    65→
    66→        if (header->type != ET_CORE) {
    67→            LOGE("Invalid Core file.\n");
    68→            return false;
    69→        }
    70→
    71→        switch(header->machine) {
    72→#if defined(__LP64__)
    73→            case EM_AARCH64:
    74→                INSTANCE = std::make_unique<arm64::Core>(map);
    75→                break;
    76→            case EM_RISCV:
    77→                INSTANCE = std::make_unique<riscv64::Core>(map);
    78→                break;
    79→            case EM_X86_64:
    80→                INSTANCE = std::make_unique<x86_64::Core>(map);
    81→                break;
    82→#endif // __LP64__
    83→            case EM_ARM:
    84→                INSTANCE = std::make_unique<arm::Core>(map);
    85→                break;
    86→            case EM_386:
    87→                INSTANCE = std::make_unique<x86::Core>(map);
    88→                break;
    89→            default:
    90→                LOGW("Not support machine (%s)\n", ElfHeader::ToMachineName(header->machine).c_str());
    91→                break;
    92→        }
    93→
    94→        if (INSTANCE) {
    95→            CoreApi::Init();
    96→            INSTANCE->mRemote = remote;
    97→            if (INSTANCE->load()) {
    98→                auto bind_file = [&](File* file) -> bool {
    99→                    LoadBlock* block = INSTANCE->findLoadBlock(file->begin(), false);
   100→                    if (block && block->vaddr() == file->begin())
   101→                        block->setFile(file->name(), file->offset());
   102→                    return false;
   103→                };
   104→                INSTANCE->foreachFile(bind_file);
   105→                if (callback) callback();
   106→                return true;
   107→            }
   108→            return false;
   109→        }
   110→    }
   111→    return false;
   112→}
