   162→uint64_t CoreApi::newLoadBlock(uint64_t vaddr, uint64_t old_size, int flags) {
   163→    int idxInLoad = 0;
   164→    int idxInQuick = 0;
   165→
   166→    uint64_t begin = RoundUp(vaddr & getVabitsMask(), ELF_PAGE_SIZE);
   167→    uint64_t size = RoundUp(old_size, ELF_PAGE_SIZE);
   168→
   169→    if (!size) {
   170→        LOGE("Can not fake malloc size 0x%" PRIx64 "\n", size);
   171→        return 0;
   172→    }
   173→
   174→    if (mLoad.empty()) {
   175→        if (!begin) begin = FAKE_LOAD_BEGIN;
   176→        if ((begin + size) > getVabitsMask()) {
   177→            LOGE("Can not fake malloc size 0x%" PRIx64 "\n", size);
   178→            return 0;
   179→        }
   180→    } else {
   181→        LoadBlock* block = findLoadBlock(begin, false);
   182→        if (block) {
   183→            LOGE("Can not fake malloc vaddr 0x%" PRIx64 "\n", begin);
   184→            return 0;
   185→        }
   186→
   187→        if (begin) {
   188→            for (; idxInLoad < mLoad.size(); ++idxInLoad) {
   189→                if (mLoad[idxInLoad]->vaddr() > begin || idxInLoad == mLoad.size() - 1) {
   190→                    uint64_t endaddr = mLoad[idxInLoad]->vaddr();
   191→                    if (idxInLoad == mLoad.size() - 1)
   192→                        endaddr = getVabitsMask();
   193→                    if ((begin + size) > endaddr) {
   194→                        LOGE("Can not fake malloc vaddr 0x%" PRIx64 ", size(0x%" PRIx64 ") bigger.\n", begin, size);
   195→                        return 0;
   196→                    }
   197→                    break;
   198→                }
   199→            }
   200→
   201→            for (; idxInQuick < mQuickLoad.size(); ++idxInQuick) {
   202→                if (mQuickLoad[idxInQuick]->vaddr() > begin)
   203→                    break;
   204→            }
   205→        } else {
   206→            std::shared_ptr<LoadBlock> left = mLoad[0];
   207→            if (FAKE_LOAD_BEGIN + size <= left->vaddr()) {
   208→                begin = FAKE_LOAD_BEGIN;
   209→            } else {
   210→                for (int idx = 1; idx < mLoad.size(); ++idx) {
   211→                    std::shared_ptr<LoadBlock> right = mLoad[idx];
   212→                    if (right->vaddr() - (left->vaddr() + left->memsz()) >= size) {
   213→                        idxInLoad = idx;
   214→                        begin = left->vaddr() + left->memsz();
   215→                        break;
   216→                    } else {
   217→                        left = right;
   218→                    }
   219→                }
   220→                if (!begin) {
   221→                    LOGE("Can not fake malloc size 0x%" PRIx64 "\n", size);
   222→                    return 0x0;
   223→                }
   224→
   225→                for (; idxInQuick < mQuickLoad.size(); ++idxInQuick) {
   226→                    if (mQuickLoad[idxInQuick]->vaddr() > begin)
   227→                        break;
   228→                }
   229→            }
   230→        }
   231→    }
   232→
   233→    std::shared_ptr<LoadBlock> block(new LoadBlock(flags,    // flags
   234→                                                   0x0,      // offset
   235→                                                   begin,    // vaddr
   236→                                                   0x0,      // paddr
   237→                                                   0x0,      // filesz
   238→                                                   size,     // memsz
   239→                                                   0x1000)); // align
   240→    block->setTruncated(false);
   241→    block->setFake(true);
   242→    block->setVabitsMask(CoreApi::GetVabitsMask());
   243→    block->setPointMask(CoreApi::GetPointMask());
   244→
   245→    if (!block->newOverlay())
   246→        return 0x0;
   247→
   248→    mLoad.insert(mLoad.begin() + idxInLoad, block);
   249→    if (!QUICK_LOAD_ENABLED || block->flags())
   250→        mQuickLoad.insert(mQuickLoad.begin() + idxInQuick, block);
   251→    return begin;
   252→}
