   338→LinkMap* CoreApi::FindLinkMap(const char* path) {
   339→    LinkMap* handle = nullptr;
   340→    LinkMap* second = nullptr;
   341→    std::filesystem::path file(path);
   342→    auto callback = [&](LinkMap* map) -> bool {
   343→        if (!strcmp(map->name(), path))
   344→            handle = map;
   345→
   346→        if (strstr(map->name(), file.filename().c_str()))
   347→            second = map;
   348→
   349→        LoadBlock* block = map->block();
   350→        if (block && block->isMmapBlock()) {
   351→            std::size_t index = block->name().find(path);
   352→            if (index != std::string::npos) {
   353→                std::filesystem::path outer(block->name());
   354→                if (file.filename() == outer.filename())
   355→                    handle = map;
   356→            }
   357→
   358→            index = block->name().find(file.filename());
   359→            if (index != std::string::npos) {
   360→                std::filesystem::path outer(block->name());
   361→                if (file.filename() == outer.filename())
   362→                    second = map;
   363→            }
   364→        }
   365→        return handle ? true : false;
   366→    };
   367→    INSTANCE->foreachLinkMap(callback);
   368→    return handle ? handle : second;
   369→}
