   379→void CoreApi::ExecFile(const char* path) {
   380→    std::vector<char *> dirs;
   381→    std::unique_ptr<char[], void(*)(void*)> newpath(strdup(path), free);
   382→    char *token = strtok(newpath.get(), ":");
   383→    while (token != nullptr) {
   384→        dirs.push_back(token);
   385→        token = strtok(nullptr, ":");
   386→    }
   387→
   388→    uint64_t phdr = FindAuxv(AT_PHDR);
   389→    api::MemoryRef execfn = FindAuxv(AT_EXECFN);
   390→    if (execfn.IsValid()) {
   391→        std::string filepath;
   392→        const char* search = reinterpret_cast<const char*>(execfn.Real());
   393→        for (char *dir : dirs) {
   394→            if (Utils::SearchFile(dir, &filepath, search))
   395→                break;
   396→        }
   397→        if (filepath.length() > 0) {
   398→            INSTANCE->exec(phdr, filepath.c_str());
   399→        }
   400→    }
   401→}
