   403→void CoreApi::SysRoot(const char* path) {
   404→    std::vector<char *> dirs;
   405→    std::unique_ptr<char[], void(*)(void*)> newpath(strdup(path), free);
   406→    char *token = strtok(newpath.get(), ":");
   407→    while (token != nullptr) {
   408→        dirs.push_back(token);
   409→        token = strtok(nullptr, ":");
   410→    }
   411→
   412→    auto callback = [dirs](LinkMap* map) -> bool {
   413→        std::unique_ptr<char[], void(*)(void*)> newname(strdup(map->name()), free);
   414→        char *ori_file = strtok(newname.get(), "!");
   415→        char *sub_file = strtok(NULL, "!");
   416→
   417→        std::string filepath;
   418→        for (char *dir : dirs) {
   419→            if (Utils::SearchFile(dir, &filepath, ori_file))
   420→                break;
   421→        }
   422→        if (filepath.length() > 0) {
   423→            if (INSTANCE->sysroot(map, filepath.c_str(), sub_file)) {
   424→                map->ReadSymbols();
   425→            }
   426→        }
   427→        return false;
   428→    };
   429→    INSTANCE->foreachLinkMap(callback);
   430→}
