   439→bool CoreApi::Read(uint64_t vaddr, uint64_t size, uint8_t* buf, int opt) {
   440→    LoadBlock* block = FindLoadBlock(vaddr);
   441→
   442→    uint64_t raddr = GetReal(vaddr, opt);
   443→    if (!raddr)
   444→        return false;
   445→
   446→    if ((vaddr + size) > (block->vaddr() + block->size())) {
   447→        uint64_t newsize = (block->vaddr() + block->size() - vaddr);
   448→        memcpy(buf, reinterpret_cast<void *>(raddr), newsize);
   449→    } else {
   450→        memcpy(buf, reinterpret_cast<void *>(raddr), size);
   451→    }
   452→    return true;
   453→}
