   486→uint64_t CoreApi::v2r(uint64_t vaddr, int opt) {
   487→    LoadBlock* block = findLoadBlock(vaddr, true);
   488→    if (block && block->isValid()) {
   489→        uint64_t raddr = block->begin(opt);
   490→        if (raddr) {
   491→            return raddr + ((vaddr & block->VabitsMask()) - block->vaddr());
   492→        } else {
   493→            return 0x0;
   494→        }
   495→    }
   496→    throw InvalidAddressException(vaddr);
   497→}
