    28→
    29→bool lp64::Core::load64(CoreApi* api, std::function<void* (OptionArgs&)> callback) {
    30→    Elf64_Ehdr *ehdr = reinterpret_cast<Elf64_Ehdr *>(api->begin());
    31→    Elf64_Phdr *phdr = reinterpret_cast<Elf64_Phdr *>(api->begin() + sizeof(Elf64_Ehdr));
    32→
    33→    for (int num = 0; num < ehdr->e_phnum; ++num) {
    34→        if (phdr[num].p_type == PT_LOAD) {
    35→            std::shared_ptr<LoadBlock> block(new LoadBlock(phdr[num].p_flags,
    36→                                             phdr[num].p_offset,
    37→                                             phdr[num].p_vaddr,
    38→                                             phdr[num].p_paddr,
    39→                                             phdr[num].p_filesz,
    40→                                             phdr[num].p_memsz,
    41→                                             phdr[num].p_align));
    42→            block->setTruncated(api->size() < (block->offset() + block->realSize()));
    43→            block->setOriAddr(api->begin() + block->offset());
    44→            block->setVabitsMask(CoreApi::GetVabitsMask());
    45→            block->setPointMask(CoreApi::GetPointMask());
    46→            api->addLoadBlock(block);
    47→        } else if (phdr[num].p_type == PT_NOTE) {
    48→            std::unique_ptr<NoteBlock> block(new NoteBlock(phdr[num].p_flags,
    49→                                             phdr[num].p_offset,
    50→                                             phdr[num].p_vaddr,
    51→                                             phdr[num].p_paddr,
    52→                                             phdr[num].p_filesz,
    53→                                             phdr[num].p_memsz,
    54→                                             phdr[num].p_align));
    55→            block->setTruncated(api->size() < (block->offset() + block->realSize()));
    56→            if (!block->isValidBlock())
    57→                continue;
    58→
    59→            block->setOriAddr(api->begin() + block->offset());
    60→            uint64_t pos = block->oraddr();
    61→            uint64_t end = block->oraddr() + block->realSize();
    62→            void *last_context = nullptr;
    63→            while (pos < end) {
    64→                Elf64_Nhdr *nhdr = reinterpret_cast<Elf64_Nhdr *>(pos);
    65→                uint64_t item_pos = nhdr->n_descsz == 0 ? 0 : pos + sizeof(Elf64_Nhdr) + RoundUp(nhdr->n_namesz, 0x4);
    66→                OptionArgs args = {
    67→                    .type = nhdr->n_type,
    68→                    .pos = item_pos,
    69→                    .context = last_context,
    70→                };
    71→                switch(nhdr->n_type) {
    72→                    case NT_PRSTATUS: {
    73→                        last_context = callback(args);
    74→                        block->addThreadItem(last_context);
    75→                    } break;
    76→                    case NT_AUXV: {
    77→                        int numauxv = nhdr->n_descsz / sizeof(lp64::Auxv);
    78→                        block->setAuxvMaxCount(numauxv);
    79→                        lp64::Auxv* auxv = reinterpret_cast<lp64::Auxv *>(item_pos);
    80→                        for (int index = 0; index < numauxv; ++index) {
    81→                            block->addAuxvItem((uint64_t)&auxv[index], auxv[index].type, auxv[index].value);
    82→                            if (!auxv[index].type) break;
    83→                        }
    84→                    } break;
    85→                    case NT_FILE: {
    86→                        uint64_t numfile = reinterpret_cast<uint64_t *>(item_pos)[0];
    87→                        uint64_t page_size = reinterpret_cast<uint64_t *>(item_pos)[1];
    88→                        lp64::File *file = reinterpret_cast<lp64::File *>(item_pos
    89→                                                        + sizeof(uint64_t) // NUMBER
    90→                                                        + sizeof(uint64_t)); // PAGE_SIZE
    91→                        uint64_t name_base = reinterpret_cast<uint64_t>(file) + sizeof(lp64::File) * numfile;
    92→                        int index = 0;
    93→                        while (index < numfile) {
    94→                            block->addFileItem(file[index].begin, file[index].end, file[index].offset, name_base);
    95→                            name_base += strlen(reinterpret_cast<const char *>(name_base)) + 1;
    96→                            ++index;
    97→                        }
    98→                    } break;
    99→                    default:
   100→                        callback(args);
   101→                        break;
   102→                }
   103→
   104→                pos = pos + sizeof(Elf64_Nhdr) + RoundUp(nhdr->n_namesz, 0x4) + RoundUp(nhdr->n_descsz, 0x4);
   105→            }
   106→
   107→            api->addNoteBlock(block);
   108→        }
   109→    }
   110→    LOGI("Core load (%p) %s\n", this, api->getName().c_str());
   111→    return true;
   112→}
   113→
   114→void lp64::Core::loadLinkMap64(CoreApi* api) {
   115→    api::MemoryRef& debug = GetDebug();
   116→    if (!debug.Ptr()) {
   117→        LOGW("Not found debug. You can try command exec.\n");
   118→        return;
   119→    }
   120→
   121→    try {
   122→        lp64::Debug* dbg = reinterpret_cast<lp64::Debug*>(debug.Real());
   123→        uint64_t map = dbg->map;
   124→        while (map) {
   125→            lp64::LinkMap* link = reinterpret_cast<lp64::LinkMap*>(CoreApi::GetReal(map));
   126→            api->addLinkMap(map);
   127→            map = link->next;
   128→        }
   129→    } catch (InvalidAddressException& e) {
   130→        LOGE("%s\n", e.what());
   131→    }
   132→}
   133→
   134→bool lp64::Core::exec64(CoreApi* api, uint64_t phdr, const char* file) {
   135→    std::unique_ptr<MemoryMap> map(MemoryMap::MmapFile(file));
   136→    if (map) {
   137→        ElfHeader* header = reinterpret_cast<ElfHeader*>(map->data());
   138→        if (!header->CheckLibrary(file))
   139→            return false;
   140→
   141→        Elf64_Ehdr* ehdr = reinterpret_cast<Elf64_Ehdr*>(map->data());
   142→        Elf64_Phdr* pt = reinterpret_cast<Elf64_Phdr*>(map->data() + sizeof(Elf64_Ehdr));
   143→
   144→        if (pt[0].p_type != PT_PHDR) {
   145→            LOGE("Exec file PHDR segment non-first\n");
   146→            return false;
   147→        }
   148→
   149→        return loader_dlopen64(api, map.get(), nullptr, phdr - ehdr->e_phoff - (pt[0].p_vaddr - pt[0].p_offset), file);
   150→    }
   151→    return false;
   152→}
   153→
   154→bool lp64::Core::dlopen64(CoreApi* api, ::LinkMap* handle, const char* file, const char* subfile) {
   155→    std::unique_ptr<MemoryMap> map(MemoryMap::MmapFile(file));
   156→    if (subfile) {
   157→        ZipFile zip;
   158→        if (zip.open(file)) {
   159→            LOGE("Zip open fail %s\n", file);
   160→            return false;
   161→        }
   162→
   163→        ZipEntry* entry;
   164→        if (subfile[0] == '/') {
   165→            entry = zip.getEntryByName(subfile + 1);
   166→        } else {
   167→            entry = zip.getEntryByName(subfile);
   168→        }
   169→        if (!entry) {
   170→            LOGE("%s Not found entry %s\n", file, subfile);
   171→            return false;
   172→        }
   173→
   174→        if (!entry->IsUncompressed()) {
   175→            LOGE("Not support compress zip %s!%s\n", file, entry->getFileName());
   176→            return false;
   177→        }
   178→
   179→        std::unique_ptr<MemoryMap> submap(MemoryMap::MmapFile(file,
   180→                                                              entry->getEntryTotalMemsz(),
   181→                                                              entry->getFileOffset()));
   182→        map = std::move(submap);
   183→    }
   184→    if (map) {
   185→        ElfHeader* header = reinterpret_cast<ElfHeader*>(map->data());
   186→        if (!header->CheckLibrary(file))
   187→            return false;
   188→
   189→        return loader_dlopen64(api, map.get(), handle, handle->l_addr(), file);
   190→    }
   191→    return false;
   192→}
   193→
   194→bool lp64::Core::loader_dlopen64(CoreApi* api, MemoryMap* map, ::LinkMap* handle, uint64_t addr, const char* file) {
   195→    if (!addr) {
   196→        LOGE("Can not loader_dlopen64 %s\n", file);
   197→        return false;
   198→    }
   199→
   200→    bool status = false;
   201→    Elf64_Ehdr* ehdr = reinterpret_cast<Elf64_Ehdr*>(map->data());
   202→    Elf64_Phdr* phdr = reinterpret_cast<Elf64_Phdr*>(map->data() + sizeof(Elf64_Ehdr));
   203→
   204→    int idx = 0;
   205→    for (int index = 0; index < ehdr->e_phnum; ++index) {
   206→        if (phdr[index].p_type != PT_LOAD)
   207→            continue;
   208→        ++idx;
   209→
   210→        if (phdr[index].p_flags & PF_W)
   211→            continue;
   212→
   213→        if (!phdr[index].p_filesz)
   214→            continue;
   215→
   216→        uint64_t current = addr + RoundDown(phdr[index].p_vaddr, CoreApi::GetPageSize());
   217→        uint64_t page_offset = RoundDown(phdr[index].p_offset + map->offset(), CoreApi::GetPageSize());
   218→
   219→        LoadBlock* block = api->findLoadBlock(current, false);
   220→        if (!block) {
   221→            LOGW("Not found %s [%d]LOAD(%" PRIx64 ")\n", file, idx, current);
   222→            continue;
   223→        }
   224→
   225→        if (idx == 1 && current == block->vaddr() && handle)
   226→            handle->GetAddrCache() = current;
   227→
   228→        if (!block->CheckCanMmap(current))
   229→            continue;
   230→
   231→        ::File* vma = CoreApi::FindFile(current);
   232→        if (vma && page_offset != vma->offset()) {
   233→            page_offset = vma->offset();
   234→        }
   235→
   236→        uint64_t mem_size = RoundUp(phdr[index].p_offset + map->offset()
   237→                                  + phdr[index].p_memsz, phdr[index].p_align);
   238→        if (mem_size < page_offset)
   239→            return status;
   240→        mem_size -= page_offset;
   241→        if (mem_size >= block->memsz()) {
   242→            block->setMmapFile(file, page_offset);
   243→            if (handle) block->bind(handle);
   244→            status = true;
   245→        } else {
   246→            LOGE("Please checksum %s miss match.\n", file);
   247→            break;
   248→        }
   249→
   250→        // continue mmap
   251→        if (mem_size > block->memsz()) {
   252→            LOGD("Mmap segment [%" PRIx64 ", %" PRIx64 ") size %" PRIx64 " != %" PRIx64 ", maybe reset range!\n",
   253→                    block->vaddr(), block->vaddr() + block->memsz(), block->memsz(), mem_size);
   254→
   255→            uint64_t cur_size = block->memsz();
   256→            while (cur_size < mem_size) {
   257→                uint64_t next = current + cur_size;
   258→                uint64_t next_page_offset = page_offset + cur_size;
   259→
   260→                LoadBlock* next_block = api->findLoadBlock(next, false);
   261→                if (!next_block) {
   262→                    LOGD("Not found next LoadBlock(%" PRIx64 ")\n", next);
   263→                    break;
   264→                }
   265→                cur_size += next_block->memsz();
   266→
   267→                if (!next_block->CheckCanMmap(next))
   268→                    continue;
   269→
   270→                ::File* next_vma = CoreApi::FindFile(next);
   271→                if (next_vma && next_page_offset != next_vma->offset()) {
   272→                    next_page_offset = next_vma->offset();
   273→                }
   274→                next_block->setMmapFile(file, next_page_offset);
   275→                if (handle) next_block->bind(handle);
   276→            }
   277→        }
   278→    }
   279→    return status;
   280→}
   281→
   282→static void ReadSymbolEntry64(std::unique_ptr<MemoryMap>& map, int symndx, int strndx,
   283→                            std::unordered_set<SymbolEntry, SymbolEntry::Hash>& symbols) {
   284→    if (!symndx || !strndx)
   285→        return;
   286→
   287→    Elf64_Ehdr* ehdr = reinterpret_cast<Elf64_Ehdr*>(map->data());
   288→    Elf64_Shdr* shdr = reinterpret_cast<Elf64_Shdr*>(map->data() + ehdr->e_shoff);
   289→
   290→    int count = shdr[symndx].sh_size / shdr[symndx].sh_entsize;
   291→    Elf64_Sym* symtab = reinterpret_cast<Elf64_Sym*>(map->data() + shdr[symndx].sh_offset);
   292→    const char* strtab = reinterpret_cast<const char*>(map->data() + shdr[strndx].sh_offset);
   293→    for (int i = 0; i < count; ++i) {
   294→        if (symtab[i].st_value && symtab[i].st_size) {
   295→            SymbolEntry entry = SymbolEntry(symtab[i].st_value, symtab[i].st_info, symtab[i].st_size,
   296→                    const_cast<const char*>(strtab + symtab[i].st_name));
   297→            // skip code section tag
   298→            if (entry.symbol == "$x")
   299→                continue;
   300→            symbols.insert(entry);
   301→        }
   302→    }
   303→}
   304→
   305→static void ReadSymbol64(std::unique_ptr<MemoryMap>& map,
   306→                         std::unordered_set<SymbolEntry, SymbolEntry::Hash>& symbols) {
   307→    if (!map) return;
   308→
   309→    int dynsymndx = 0;
   310→    int dynstrndx = 0;
   311→    int symtabndx = 0;
   312→    int strtabndx = 0;
   313→
   314→    // already check truncated
   315→    Elf64_Ehdr* ehdr = reinterpret_cast<Elf64_Ehdr*>(map->data());
   316→    Elf64_Shdr* shdr = reinterpret_cast<Elf64_Shdr*>(map->data() + ehdr->e_shoff);
   317→    const char* shstr = reinterpret_cast<const char*>(map->data() + shdr[ehdr->e_shstrndx].sh_offset);
   318→
   319→    int sh_num = ehdr->e_shnum;
   320→    for (int i = 0; i < sh_num; ++i) {
   321→        uint64_t addr = reinterpret_cast<uint64_t>(shstr + shdr[i].sh_name);
   322→        if (addr < map->data() || addr >= (map->data() + map->size()))
   323→            continue;
   324→
   325→        if (shdr[i].sh_type == SHT_NOBITS)
   326→            continue;
   327→
   328→        if (!strcmp(shstr + shdr[i].sh_name, ".dynsym")) {
   329→            dynsymndx = i;
   330→            continue;
   331→        }
   332→
   333→        if (!strcmp(shstr + shdr[i].sh_name, ".dynstr")) {
   334→            dynstrndx = i;
   335→            continue;
   336→        }
   337→
   338→        if (!strcmp(shstr + shdr[i].sh_name, ".symtab")) {
   339→            symtabndx = i;
   340→            continue;
   341→        }
   342→
   343→        if (!strcmp(shstr + shdr[i].sh_name, ".strtab")) {
   344→            strtabndx = i;
   345→            continue;
   346→        }
   347→    }
   348→
   349→    ReadSymbolEntry64(map, dynsymndx, dynstrndx, symbols);
   350→    ReadSymbolEntry64(map, symtabndx, strtabndx, symbols);
   351→}
   352→
   353→void lp64::Core::readsym64(::LinkMap* handle) {
   354→    if (!handle->block())
   355→        return;
   356→
   357→    std::unique_ptr<MemoryMap> map(MemoryMap::MmapFile(handle->block()->name().c_str(), handle->block()->GetMmapOffset()));
   358→    std::unordered_set<SymbolEntry, SymbolEntry::Hash>& symbols = handle->block()->GetSymbols();
   359→    if (map) {
   360→        // already check valid on dlopen
   361→        int gnu_debugdatandx = 0;
   362→
   363→        Elf64_Ehdr* ehdr = reinterpret_cast<Elf64_Ehdr*>(map->data());
   364→        if (ehdr->e_shoff > map->size()) {
   365→            LOGW("%s mmap file is truncated or no match.\n", map->getName().c_str());
   366→            return;
   367→        }
   368→
   369→        Elf64_Shdr* shdr = reinterpret_cast<Elf64_Shdr*>(map->data() + ehdr->e_shoff);
   370→        if (shdr[ehdr->e_shstrndx].sh_offset > map->size()) {
   371→            LOGW("%s mmap file is truncated or no match.\n", map->getName().c_str());
   372→            return;
   373→        }
   374→
