class LinkMap;

class LoadBlock : public Block {
public:
    inline uint64_t begin() { return begin(OPT_READ_ALL); }
    inline uint64_t begin(int opt) {
        if (UNLIKELY(mOverlay && (opt & OPT_READ_OVERLAY)))
            return mOverlay->data();
        if (UNLIKELY(mMmap && (opt & OPT_READ_MMAP)))
            return mMmap->data();
        if (LIKELY(oraddr() && (opt & OPT_READ_OR)))
            return oraddr();
        return 0x0;
    }
    inline uint64_t size() { return size(OPT_READ_ALL); }
    inline uint64_t size(int opt) {
        if (UNLIKELY(mOverlay && (opt & OPT_READ_OVERLAY)))
            return mOverlay->size();
        if (UNLIKELY(mMmap && (opt & OPT_READ_MMAP)))
            return mMmap->size();
        if (LIKELY(oraddr() && (opt & OPT_READ_OR)))
            return realSize();
        return 0x0;
    }
    inline bool isValid() {
        if ((isValidBlock() || mMmap || mOverlay))
            return true;
        return false;
    }
    inline bool virtualContains(uint64_t addr) {
        uint64_t clocaddr = addr & mVabitsMask;
        if ((clocaddr < vaddr())
                || (clocaddr >= (vaddr() + size())))
            return false;
        return true;
    }
    inline bool realContains(uint64_t raddr) {
        if (mOverlay) {
            return (raddr >= mOverlay->data() && raddr < (mOverlay->data() + size()));
        } else if (mMmap) {
            return (raddr >= mMmap->data() && raddr < (mMmap->data() + size()));
        } else if (oraddr()) {
            return (raddr >= oraddr() && raddr < (oraddr() + size()));
        }
        return false;
    }

    inline std::string convertValids() {
        std::string valid;
        if (isValid()) {
            valid.append("[*]");
            if (realSize() && realSize() != memsz()) {
                valid.append("(MEMSZ ");
                valid.append(Utils::ToHex(memsz()));
                valid.append(")");
            }
            if (isMmapBlock()) {
                valid.append("(MMAP");
                if (GetMmapOffset()) {
                    valid.append(" ");
                    valid.append(Utils::ToHex(GetMmapOffset()));
                }
                valid.append(")");
            }
            if (isOverlayBlock()) {
                valid.append("(OVERLAY)");
                if (isFake())
                    valid.append("(FAKE)");
            }
        } else {
            valid.append("[EMPTY]");
            if (isTruncated())
                valid.append("(TRUNCATE)");
        }
        return valid;
    }

    LoadBlock(uint32_t f, uint64_t off, uint64_t va, uint64_t pa,
            uint64_t filesz, uint64_t memsz, uint64_t align)
            : Block(f, off, va, pa, filesz, memsz, align) {
        mVabitsMask = 0x0;
        mPointMask = 0x0;
        mCRC32 = 0x0;
        mLinkMap = nullptr;
    }

    void setMmapFile(const char* file, uint64_t offset);
    void setOverlay(uint64_t addr, void *buf, uint64_t size);
    bool newOverlay();
    void removeMmap();
    void removeOverlay();
    inline bool isMmapBlock() { return mMmap != nullptr; }

